public int active()
{
    int ret;

    FormDataSource   ProdParmReportFinished_ds;
    ret =  next Active();
    ProdParmReportFinished_ds = this;

    ProdParmReportFinished_ds.object(fieldNum(ProdParmReportFinished,PostedQty)).allowEdit(false);
    ProdParmReportFinished_ds.formRun().design().controlName(formControlStr(ProdParmReportFinished,BatchNumber)).visible(!ETGCanadaParameters::find().EnableExcludeCustomizations);
    ProdParmReportFinished_ds.formRun().design().controlName(formControlStr(ProdParmReportFinished,CustomNewButton)).enabled(!ETGCanadaParameters::find().EnableExcludeCustomizations);
    ProdParmReportFinished_ds.formRun().design().controlName(formControlStr(ProdParmReportFinished,customRemoveButton)).enabled(!ETGCanadaParameters::find().EnableExcludeCustomizations);
    return ret;
}
